#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double q, p;
        scanf("%lf %lf", &q, &p);
        double total = q * p;
        if (q > 1000) total *= 0.9;
        printf("%.6f\n", total);
    }
    return 0;
}

